  function _mix(a, b, t) { var x = _toRgb(a), y = _toRgb(b); return _toHex([x[0] + (y[0] - x[0]) * t, x[1] + (y[1] - x[1]) * t, x[2] + (y[2] - x[2]) * t]); }
