    '.sst-head{display:flex;align-items:center;gap:12px;padding:16px 20px;background:linear-gradient(135deg,#1c1f2b,#23202e);border-bottom:1px solid #2a2d3a;position:sticky;top:0;z-index:5}',
    '.sst-head h1{font-size:18px;margin:0;font-weight:700;letter-spacing:.2px}',
    '.sst-head .sub{color:#9aa0b4;font-size:12px}',
    '.sst-x{margin-left:auto;background:#2a2d3a;border:none;color:#e7e9f0;border-radius:8px;width:34px;height:34px;font-size:18px;cursor:pointer}',
    '.sst-x:hover{background:#3a3e52}',
    '.sst-body{padding:18px 20px 28px}',
    '.sst-card{background:#1a1d27;border:1px solid #262a38;border-radius:12px;padding:16px;margin:0 0 16px}',
    '.sst-card>h2{margin:0 0 4px;font-size:15px;display:flex;align-items:center;gap:8px}',
    '.sst-card>.hint{color:#8a90a6;font-size:12px;margin:0 0 12px}',
    '.sst-row{display:flex;gap:10px;flex-wrap:wrap;align-items:center}',
    '.sst-lbl{display:flex;flex-direction:column;gap:4px;flex:1 1 220px;min-width:0}',
    '.sst-lbl>span{font-size:12px;color:#b9bed0;display:flex;align-items:center;gap:6px}',
    '.sst-in,.sst-ta,.sst-sel{background:#0f1118;border:1px solid #2c3040;color:#e7e9f0;border-radius:8px;padding:8px 10px;font:13px system-ui,sans-serif;width:100%}',
    '.sst-ta{min-height:54px;resize:vertical}',
    '.sst-in:focus,.sst-ta:focus,.sst-sel:focus{outline:none;border-color:#7b5cff}',
    '.sst-q{display:inline-flex;align-items:center;justify-content:center;width:16px;height:16px;border-radius:50%;background:#2c3040;color:#aab;font-size:11px;cursor:help;border:none;flex:0 0 auto}',
    '.sst-q:hover{background:#7b5cff;color:#fff}',
    '.sst-btn{background:#2a2d3a;border:1px solid #343849;color:#e7e9f0;border-radius:8px;padding:8px 14px;font:600 13px system-ui;cursor:pointer}',
    '.sst-btn:hover{background:#343849}',
    '.sst-btn.pri{background:linear-gradient(135deg,#7b5cff,#e85d8a);border:none}',
    '.sst-btn.pri:hover{filter:brightness(1.08)}',
    '.sst-btn.sm{padding:4px 10px;font-size:12px}',
    '.sst-pick{display:grid;grid-template-columns:repeat(auto-fill,minmax(150px,1fr));gap:8px;max-height:min(660px,70vh);overflow:auto;overscroll-behavior:contain;padding:4px;border:1px solid #262a38;border-radius:10px;background:#0f1118}',
    '.sst-pick-sized{grid-template-columns:repeat(auto-fill,minmax(var(--sst-mood-pick-min,150px),1fr))}',
    '.sst-pick-div{grid-column:1/-1;font-size:11px;font-weight:700;color:#7b5cff;text-transform:uppercase;letter-spacing:.5px;margin:8px 2px 0;padding-top:7px;border-top:1px solid #2a2d3a;position:sticky;left:0}',
    '.sst-pick-div:first-child{border-top:none;margin-top:2px;padding-top:0}',
    '.sst-opt{padding:8px 10px;border-radius:8px;background:#171a24;border:1px solid #262a38;cursor:pointer}',
    '.sst-opt:hover{border-color:#7b5cff}',
    '.sst-opt.greyed{opacity:.4;cursor:not-allowed}',
    '.sst-opt .nm{font-weight:600;font-size:13px}',
    '.sst-opt .ds{color:#8a90a6;font-size:11px;margin-top:2px}',
    '.sst-tl{position:relative;height:42px;border-radius:8px;overflow:hidden;border:1px solid #2c3040;background:#0f1118;-webkit-user-select:none;user-select:none;touch-action:pan-y}',
    '.sst-tl-seg{position:absolute;top:0;bottom:0;display:flex;align-items:center;justify-content:center;overflow:hidden;white-space:nowrap;pointer-events:auto;cursor:pointer;font-size:11px;color:#fff;text-shadow:0 1px 2px rgba(0,0,0,.55);box-shadow:inset -1px 0 0 rgba(0,0,0,.3)}',
    '.sst-tl-seg.hot{filter:brightness(1.22)}',
    '.sst-tl-num{font-size:11px;font-weight:700;color:#fff;text-shadow:0 1px 2px rgba(0,0,0,.6);pointer-events:none}',
    // colour KEY below the timeline bar
    '.sst-tl-key{display:flex;flex-wrap:wrap;gap:5px 6px;margin-top:11px}',
    '.sst-tl-key-item{display:inline-flex;align-items:center;gap:7px;padding:4px 10px 4px 7px;border-radius:8px;background:#171a24;border:1px solid #242836;cursor:pointer;transition:background .12s,border-color .12s,box-shadow .12s}',
    '.sst-tl-key-item:hover{background:#1e2230}',
    '.sst-tl-key-item.hot{border-color:#7b5cff;background:#211d33;box-shadow:0 0 0 1px #7b5cff}',
    '.sst-tl-key-dot{width:11px;height:11px;border-radius:4px;flex:0 0 auto;box-shadow:0 0 0 1px rgba(255,255,255,.1)}',
    '.sst-tl-key-n{font-size:10px;color:#6b7180;font-variant-numeric:tabular-nums;min-width:15px;text-align:right}',
