    '.sst-cl-pct{font-size:12px;color:#9aa0b4;font-variant-numeric:tabular-nums;min-width:40px;text-align:right;flex:0 0 auto}',
    // full-width (fullscreen) timeline view
    '.sst-tl-fs-panel{width:min(1900px,98vw);background:#14161d;border:1px solid #2a2d3a;border-radius:14px;box-shadow:0 20px 60px rgba(0,0,0,.55);padding:20px;margin:auto}',
    '.sst-tl-fs-head{display:flex;align-items:center;gap:14px;margin-bottom:16px;flex-wrap:wrap}',
    '.sst-tl-fs-head h2{margin:0;font-size:16px}',
