    '.sst-tl-fs .sst-tl-h{width:18px;margin-left:-9px}',
    '.sst-tl-fs .sst-tl-num{font-size:13px}',
    // vertical (rotated) full-width bar — for portrait monitors
    '.sst-tl-fs-v{height:min(74vh,920px);width:120px;margin:0 auto}',
    '.sst-tl-fs-v .sst-tl-h-v{width:auto;left:0;right:0;bottom:auto;height:20px;margin-left:0;margin-top:-10px;cursor:ns-resize}',
    '.sst-tl-fs-v .sst-tl-h-v::after{left:20%;right:20%;top:50%;bottom:auto;width:auto;height:2px;margin-top:-1px}',
    '.sst-tl-fs-v .sst-tl-h-v:hover::after,.sst-tl-fs-v .sst-tl-h-v:active::after{height:3px}',
    '.sst-tl-h{position:absolute;top:0;bottom:0;width:12px;margin-left:-6px;cursor:ew-resize;z-index:2}',
    '.sst-tl-h::after{content:"";position:absolute;left:4px;top:20%;bottom:20%;width:2px;background:rgba(255,255,255,.45);border-radius:1px}',
    '.sst-tl-h:hover::after,.sst-tl-h:active::after{background:#fff;left:3px;width:3px}',
    '.sst-chip{display:inline-flex;align-items:center;gap:6px;background:#222634;border:1px solid #313650;border-radius:14px;padding:3px 6px 3px 10px;font-size:12px;margin:3px 4px 3px 0}',
    '.sst-chip button{background:none;border:none;color:#9aa0b4;cursor:pointer;font-size:14px;line-height:1}',
    '.sst-chip button:hover{color:#e85d8a}',
    // ── "⤢ Edit all at a glance" full-screen split editor ──
    '.sst-sf-body{display:flex;flex:1;min-height:0}',
    '.sst-sf-left{overflow:auto;padding:14px;min-width:0}',
    '.sst-sf-div{flex:0 0 8px;cursor:ew-resize;background:#262a38;touch-action:none}',
    '.sst-sf-div:hover,.sst-sf-div:active{background:#7b5cff}',
    '.sst-sf-right{flex:1 1 auto;overflow:auto;padding:14px;min-width:0;border-left:1px solid #1e2230}',
    '.sst-sf-sec{border:1px solid #262a38;border-radius:10px;padding:10px 12px;margin:0 0 10px;background:#171a24;transition:border-color .1s,box-shadow .1s}',
    '.sst-sf-sec.drop-hot{border-color:#7b5cff;box-shadow:0 0 0 2px rgba(123,92,255,.35) inset;background:#1b1a2b}',
    '.sst-sf-lbl{font-size:11px;color:#8a90a6;text-transform:uppercase;letter-spacing:.4px;margin:6px 0 3px;font-weight:700}',
    '.sst-sf-chips{display:flex;flex-wrap:wrap;gap:2px;align-items:center;min-height:22px}',
    '.sst-sf-pal{display:grid;grid-template-columns:repeat(auto-fill,minmax(var(--sst-sf-pal-min,94px),1fr));gap:6px}',
    '.sst-sf-tile{position:relative;aspect-ratio:1;border-radius:9px;border:1px solid #262a38;background:#0f1118 center/cover no-repeat;cursor:grab;overflow:hidden;touch-action:none;display:flex;align-items:flex-end;padding:5px}',
    '.sst-sf-tile:hover{border-color:#7b5cff}',
    '.sst-sf-tile:active{cursor:grabbing}',
    '.sst-sf-tile-lbl{font-size:11px;line-height:1.15;color:#e7e9f0;text-shadow:0 1px 3px rgba(0,0,0,.9),0 0 3px rgba(0,0,0,.7);word-break:break-word}',
    '.sst-sf-tile.has-img .sst-sf-tile-lbl{width:100%;background:linear-gradient(transparent,rgba(0,0,0,.6));padding:2px 4px;border-radius:4px}',
    '.sst-sf-ghost{position:fixed;z-index:2147483646;pointer-events:none;opacity:.92;width:76px;height:76px;border-radius:9px;border:2px solid #7b5cff;background:#171a24 center/cover no-repeat;display:flex;align-items:center;justify-content:center;font-size:11px;color:#fff;text-align:center;padding:4px;box-shadow:0 8px 24px rgba(0,0,0,.5)}',
    '.sst-sf-tools{display:flex;gap:8px;flex-wrap:wrap;align-items:center;padding:8px 14px;border-bottom:1px solid #1e2230;background:#12141c}',
    '.sst-sf-minis{display:flex;flex-wrap:wrap;gap:5px}',
    '.sst-sf-mini{position:relative;width:var(--sst-sf-mini,66px);height:var(--sst-sf-mini,66px);border-radius:8px;border:1px solid #262a38;background:#0f1118 center/cover no-repeat;overflow:hidden;display:flex;align-items:flex-end;padding:3px}',
    '.sst-sf-mini .sst-sf-tile-lbl{font-size:9px;line-height:1.1}',
    '.sst-sf-mini.has-img .sst-sf-tile-lbl{width:100%;background:linear-gradient(transparent,rgba(0,0,0,.7));padding:1px 3px;border-radius:3px}',
    '.sst-sf-mini-x{position:absolute;top:1px;right:1px;width:17px;height:17px;line-height:15px;text-align:center;border-radius:50%;background:rgba(20,22,29,.85);border:none;color:#e85d8a;cursor:pointer;font-size:13px;padding:0}',
    '.sf-nodiv .sst-sf-pal,.sf-nodiv .sst-sf-minis{gap:0}',
    '.sf-nodiv .sst-sf-tile,.sf-nodiv .sst-sf-mini{border-radius:0;border-color:transparent}',
    '.sst-sf-tile-fav{position:absolute;top:3px;right:4px;display:flex;gap:6px;z-index:2;font-size:14px;line-height:1;text-shadow:0 1px 3px rgba(0,0,0,.95)}',
    '.sst-sf-mini-wrap{display:flex;flex-direction:column;align-items:center;gap:2px}',
    '.sst-sf-w{display:inline-flex;align-items:center;gap:3px;margin-left:5px}',
    '.sst-sf-mini-wrap .sst-sf-w{margin-left:0}',
    '.sst-sf-w-lbl{font-size:10px;color:#a78bfa;font-variant-numeric:tabular-nums;min-width:34px;text-align:center}',
