    '.sst-thumbsize{display:inline-flex;align-items:center;gap:6px;font-size:12px;color:#9aa0b4;padding:0 4px}',
    '.sst-thumbsize input[type=range]{width:96px;accent-color:#7b5cff;cursor:pointer;vertical-align:middle}',
    '.sst-thumbsize-lbl{white-space:nowrap;min-width:78px}',
    '.sst-sf-w-btn:hover{background:#343849}',
    '.sst-sec{border:1px solid #262a38;border-radius:10px;margin:0 0 10px;overflow:hidden}',
