    // Per-section per-mood strength (user spec 2026-07-01): STACKS on the global per-mood weight.
    // effective = clamp(globalWeight + sectionDelta, 0, cap); cap = 15 for dark moods else 50.
    function _secGlobalW(n) { return +(gv('mood_weights', {}) || {})[n] || 0; }
    function _secCap(n) { return (V2TONE[n] === 'dark') ? 15 : 50; }
