  // ── Positions in a part (Option A, 2026-07-02): default positions are REMOVABLE. s.excludePositions =
  //    the default pose-strings the patron removed for THIS part; effective = defaults-minus-excluded + added. ──
  function _posNorm(x) { return String(x == null ? '' : x).toLowerCase().replace(/[^a-z0-9]/g, ''); }
