    var row = el('div', { class: 'hint', style: { margin: '4px 0 0', fontSize: '11px', display: 'flex', flexWrap: 'wrap', gap: '4px', alignItems: 'center' } }, [el('span', { text: t('Removed (click to add back): ') })]);
    exd.forEach(function (p) { row.appendChild(el('span', { class: 'sst-chip', style: { cursor: 'pointer', opacity: '.65', textDecoration: 'line-through' }, title: t('Add this position back to the part'), onclick: function () { restorePartDefault(s, p); saveDraft(); onChange(); } }, [t(spaceForm(p)) + ' ↺'])); });
