  // fields the inline editors do: s.moods / s.moodMode / s.addPositions.
  var _posThumbCache = {};                 // "char/positions/key_idx" → objectURL|null
  var _sfCards = null, _sfThumbsLeft = false, _sfThumbsLeftPos = true, _sfRefreshAll = null;   // live cards; left-thumbnails flags (moods / positions have their OWN toggle); refresh-both-panels cb
  var _pickRedraw = null;   // FSA-REVOKE-01: the open "Add a mood/position" picker's drawGrid, so a folder change repaints ITS tiles too
  // FSA-REVOKE-01: resetThumbCaches() (called inside connectAndCache) revokes EVERY shared _thumbCache/_posThumbCache
  // objectURL, but those blob: URLs are also painted onto tiles of OTHER open surfaces (the Add-a-mood grid, the
