    b = Math.max(a, b); cc = Math.max(b, cc);
    var sl = zoneSlider({ zones: [{ label: 'Triple', color: ZC.tp }, { label: 'Double', color: ZC.dp }, { label: 'Spitroast', color: ZC.spit }, { label: 'Normal', color: ZC.normal }], handles: [a, b, cc],
      onChange: function (h) { ST.controls.gangbang_tp_pct = h[0]; ST.controls.gangbang_dp_pct = h[1]; ST.controls.gangbang_tpspit_pct = h[2]; saveDraft(); } });
