    var a = el('a', { href: url, download: ST.story.replace(/[^a-z0-9]+/gi, '_') + '_patron_custom.json' });
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    setTimeout(function () { URL.revokeObjectURL(url); }, 4000);
